<?php $foodCategories = rt2027_food_categories($pdo, false); $selectedCategoryId = (int)($pantryEdit['category_id'] ?? 0); if (!$selectedCategoryId && !empty($pantryEdit['category'])) { foreach ($foodCategories as $fc) { if (mb_strtolower($fc['name']) === mb_strtolower((string)$pantryEdit['category'])) { $selectedCategoryId = (int)$fc['id']; break; } } } ?>
<?php $pageTitle = 'Alimentação • Despensa'; ?>
<div class="rt-admin-shell"><?php include __DIR__ . '/../partials/admin_sidebar.php'; ?><main class="rt-admin-content p-4 lg:p-8"><div class="rt-admin-topbar rounded-3xl"><div><div class="rt-admin-title">Despensa</div><div class="rt-admin-subtitle">Cadastre os itens do estoque e acompanhe alertas de quantidade mínima.</div></div></div>
<?php if ($msg = flash('success')): ?><div class="mb-4 rounded-2xl bg-emerald-50 border border-emerald-200 text-emerald-800 px-4 py-3"><?= $msg ?></div><?php endif; ?><?php if ($msg = flash('error')): ?><div class="mb-4 rounded-2xl bg-red-50 border border-red-200 text-red-800 px-4 py-3"><?= $msg ?></div><?php endif; ?>
<div class="grid grid-cols-1 xl:grid-cols-3 gap-6"><div class="xl:col-span-1 rt-card rounded-3xl p-5"><h2 class="text-xl font-semibold mb-4"><?= $pantryEdit ? 'Editar item' : 'Novo item da despensa' ?></h2><form method="post" action="index.php?route=admin/food-pantry-save" class="space-y-4"><input type="hidden" name="_csrf" value="<?= h(csrf_token()) ?>"><input type="hidden" name="id" value="<?= h($pantryEdit['id'] ?? '') ?>"><div><label>Item</label><input type="text" name="item_name" value="<?= h($pantryEdit['item_name'] ?? '') ?>"></div><div><label>Categoria</label><select name="category_id"><option value="">Selecione</option><?php foreach ($foodCategories as $cat): ?><option value="<?= h($cat['id']) ?>" <?= $selectedCategoryId === (int)$cat['id'] ? 'selected' : '' ?>><?= h($cat['name']) ?></option><?php endforeach; ?></select><input type="hidden" name="category" value="<?= h($pantryEdit['category'] ?? '') ?>"><div class="text-xs text-slate-500 mt-2">Gerencie as opções em <a class="font-semibold text-teal-700" href="index.php?route=admin/food-categories">Categorias</a>.</div></div><div class="grid grid-cols-2 gap-4"><div><label>Unidade</label><input type="text" name="unit" value="<?= h($pantryEdit['unit'] ?? '') ?>" placeholder="kg, un"></div><div><label>Quantidade atual</label><input type="number" step="0.01" name="quantity_current" value="<?= h($pantryEdit['quantity_current'] ?? 0) ?>"></div><div><label>Estoque mínimo</label><input type="number" step="0.01" name="minimum_stock" value="<?= h($pantryEdit['minimum_stock'] ?? 0) ?>"></div><div><label>Validade</label><input type="date" name="expiration_date" value="<?= h($pantryEdit['expiration_date'] ?? '') ?>"></div></div><div><label>Local de armazenamento</label><input type="text" name="storage_place" value="<?= h($pantryEdit['storage_place'] ?? '') ?>"></div><div><label>Observações</label><textarea name="notes" rows="3"><?= h($pantryEdit['notes'] ?? '') ?></textarea></div><div class="flex gap-3"><button class="rt-btn-primary rounded-full px-5 py-3 font-semibold" type="submit">Salvar</button><a class="rt-btn-secondary rounded-full px-5 py-3 font-semibold" href="index.php?route=admin/food-pantry">Novo</a></div></form></div>
<div class="xl:col-span-2 rt-card rounded-3xl p-5 overflow-x-auto"><h2 class="text-xl font-semibold mb-4">Itens cadastrados</h2><table class="min-w-full text-sm"><thead><tr class="text-left text-slate-500"><th class="py-2 pr-4">Item</th><th class="py-2 pr-4">Categoria</th><th class="py-2 pr-4">Estoque</th><th class="py-2 pr-4">Mínimo</th><th class="py-2 pr-4">Local</th><th class="py-2 pr-4"></th></tr></thead><tbody><?php foreach ($pantryItems as $item): $isLow=(float)$item['quantity_current'] <= (float)$item['minimum_stock']; ?><tr class="border-t border-slate-200 <?= $isLow ? 'bg-amber-50' : '' ?>"><td class="py-3 pr-4 font-semibold"><?= h($item['item_name']) ?></td><td class="py-3 pr-4"><?= h($item['category_display'] ?? $item['category'] ?? '') ?></td><td class="py-3 pr-4"><?= rt2027_format_quantity($item['quantity_current'], $item['unit']) ?> <?= h($item['unit']) ?></td><td class="py-3 pr-4"><?= rt2027_format_quantity($item['minimum_stock'], $item['unit']) ?> <?= h($item['unit']) ?></td><td class="py-3 pr-4"><?= h($item['storage_place']) ?></td><td class="py-3 pr-4"><div class="flex gap-3"><a class="font-semibold text-teal-700" href="index.php?route=admin/food-pantry&id=<?= h($item['id']) ?>">Editar</a><form method="post" action="index.php?route=admin/food-pantry-delete" onsubmit="return confirm('Excluir este item?');"><input type="hidden" name="_csrf" value="<?= h(csrf_token()) ?>"><input type="hidden" name="id" value="<?= h($item['id']) ?>"><button class="font-semibold text-red-700" type="submit">Excluir</button></form></div></td></tr><?php endforeach; ?></tbody></table><?php if (!$pantryItems): ?><div class="text-slate-500">Nenhum item na despensa ainda.</div><?php endif; ?></div></div></main></div>
